import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import layout2Styles from '../styles/layout2.module.css';
import bookCardsStyles from '../styles/bookCards.module.css';

function InventoryPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchBooks = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get('/api/books', config);
        setBooks(data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch inventory');
      } finally {
        setLoading(false);
      }
    };

    fetchBooks();
  }, []);

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString();
  };

  if (loading) {
    return <EmployeeLayout title="Inventory"><div>Loading...</div></EmployeeLayout>;
  }

  return (
    <EmployeeLayout title="Inventory">
      <div style={{ marginBottom: '1.5rem', display: 'flex', justifyContent: 'flex-end' }}>
        <Link to="/insertbook" className={layout2Styles.menuItem} style={{ backgroundColor: '#004085', color: 'white' }}>
          Add New Book
        </Link>
      </div>
      {error && <p className={layout2Styles.error}>{error}</p>}
      <div className={bookCardsStyles.inventoryContainer}>
        {books.map((book) => (
          <div key={book._id} className={bookCardsStyles.bookCard}>
            <div className={bookCardsStyles.coverArtSection}>
              <img src={book.coverArt || '/images/cover-placeholder.png'} alt={`${book.seriesTitle} #${book.issueNumber}`} />
            </div>
            <div className={bookCardsStyles.bookDetails}>
              <h3>{book.seriesTitle} #{book.issueNumber}</h3>
              <p className={bookCardsStyles.detailItem}><strong>Publisher:</strong> {book.publisher || 'N/A'}</p>
              <p className={bookCardsStyles.detailItem}><strong>Release Date:</strong> {formatDate(book.releaseDate)}</p>
              <p className={bookCardsStyles.detailItem}><strong>Series Start:</strong> {formatDate(book.seriesStartDate)}</p>
              <p className={bookCardsStyles.detailItem}><strong>Series End:</strong> {formatDate(book.seriesEndDate)}</p>
              <div className={bookCardsStyles.tags}>
                {book.tags.map((tag, index) => <span key={index} className={bookCardsStyles.tag}>{tag}</span>)}
              </div>
              <div className={bookCardsStyles.cardActions}>
                <Link to={`/editbook/${book._id}`} className={layout2Styles.menuItem} style={{ backgroundColor: '#5a6268', color: 'white' }}>Edit</Link>
              </div>
            </div>
          </div>
        ))}
      </div>
    </EmployeeLayout>
  );
}

export default InventoryPage;
